import React from 'react';
import {
    Container, Table,
    Button,
    Row, Col,
    ButtonGroup,
    Form, FormControl, InputGroup,
    // Dropdown, Pagination, Modal,
} from 'react-bootstrap';

import {
    FaTimes,
    FaTired, FaSmileBeam, FaMeh,
    // FaPhoneSquare, FaFax,
    // FaRegEnvelope, FaTrash, FaEdit,
    // FaPlus,
    // FaAngleLeft, FaAngleRight,
    // FaExclamationCircle, FaCheckCircle,
} from 'react-icons/fa';
import VendorDropdown from './VendorDropdown';
import { UserContext } from './user-context.js';
import { IconContext } from "react-icons";
import PartHistory from './PartHistory.js';
import DatePicker from 'react-date-picker';

// const config = require('./config.js');
const apiUrl = process.env.REACT_APP_API_URL;
const dateFormat = require('dateformat');
// const util = require('./util.js');

export default class StockIn extends React.Component {
    constructor(...args) {
        super(...args);
        this.state = {
            amount: 1,
            q: '',
            // q: 'EE-0006',
            part: null,
            buttonDisabled: false,
            date: new Date(),
        }
    }

    searchChangeHandler = (e) => {
        this.setState({ q: e.target.value });
    }

    clearSearch = (e) => {
        this.setState({
            part: null,
            transactions: null,
            q: ''
        });
    }

    searchPart = () => {
        let partCode = this.state.q;
        console.log("Searching ", partCode);
        if (partCode === '') return;
        this.fetchPart(partCode);
        this.setState({
            buttonDisabled: true
        });
    }

    fetchPart(partCode) {
        let url = apiUrl + 'part/search/code/' + partCode;

        fetch(url,
            {
                // fetch(apiUrl + 'part', {
                method: 'GET',
                headers: {
                    'Accept': 'application/json',
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                }
            })
            .then(response => response.json())
            .then(jsonData => {
                console.log('StockIn fetchPart:', jsonData.data);
                let vendorId = jsonData.data.vendor ? jsonData.data.vendor._id : null;
                // let partId = jsonData.data._id;
                this.setState({
                    part: jsonData.data,
                    buttonDisabled: false,
                    vendorId: vendorId,
                    price: jsonData.data.latestPrice
                });
                /*
                                util.fetchTransactions(partId,
                                    (res) => {
                                        console.log('fetchTransactions', res);
                                        this.setState({
                                            transactions: res.data
                                        });
                                    },
                                    (err) => {
                                        console.error(err);
                                    })
                                    */
            })
            .catch(error => {
                console.error('Error:', error);
            });
    }

    changeHandler = (e) => {
        console.log('changeHandler', e.target.id, e.target.value)
        this.setState({
            [e.target.id]: e.target.value
        })
    }


    selectVendorHandler = (vendorId) => {
        console.log("handleSelect", vendorId);
        this.setState({
            vendorId: vendorId
        });
    }


    submitHandler = event => {
        if (!window.confirm('ข้อมูลถูกต้องแล้วใช่หรือไม่?')) {
            event.stopPropagation();
            return;
        }
        const form = event.currentTarget;
        event.preventDefault();
        if (form.checkValidity() === false) {
            event.stopPropagation();
        }

        let part = this.state.part;
        console.log('amount', part.currentAmount, this.state.amount)

        let method = 'POST';
        console.log(method, this.state);
        console.log(part);
        // @TODO include this into util
        fetch(apiUrl + 'transaction', {
            method: method,
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            body: JSON.stringify({
                code: this.state.part.code,
                date: this.state.date,
                part: this.state.part._id,
                user: this.context._id,
                amount: this.state.amount,
                vendor: this.state.vendorId,
                price: this.state.price,
                currentAmount: this.state.part.currentAmount
            })
        })
            .then(response => response.json())
            .then(jsonData => {
                alert("เพิ่มจำนวนแล้ว")
                console.log('submitHandler Success:', jsonData);
                this.searchPart(part.code);
                this.setState({
                    // part: jsonData.part,
                    buttonDisabled: true
                });
            })
            .catch(error => {
                console.error('Error:', error);
            });

    };

    render() {

        let part = this.state.part;
        let user = this.context;

        if (part) {
            part.vendorName = part.vendor !== undefined && part.vendor !== null ? part.vendor.name : '';
        }

        return (
            <>
                <Container>
                    <h2>บันทึกของเข้า</h2>
                    Record by: {user.name}
                    {/* {user._id} */}
                    <Row>
                        <InputGroup className="mb-3">
                            <FormControl
                                placeholder="ค้นหาด้วย CODE"
                                aria-label="ค้นหาด้วย CODE"
                                aria-describedby="basic-addon2"
                                value={this.state.q}
                                onChange={this.searchChangeHandler}
                                onKeyPress={event => {
                                    if (event.key === "Enter") {
                                        this.searchPart();
                                    }
                                }}
                            />
                            <InputGroup.Append>
                                <Button variant="outline-secondary"
                                    onClick={this.searchPart}>
                                    ค้นหา
                                </Button>
                                <Button variant="outline-secondary"
                                    onClick={this.clearSearch}>
                                    <FaTimes />
                                </Button>
                            </InputGroup.Append>
                        </InputGroup>
                    </Row>
                    <Form onSubmit={this.submitHandler}>
                        {this.state.part &&
                            <>
                                <h2 style={{ color: 'blue' }}>{part.code} : {part.name}</h2>

                                <Table striped bordered hover size="sm">
                                    <thead>
                                        <tr>
                                            {/* <th>Part NO.</th>
                                            <th>Part Name</th> */}
                                            <th>Date</th>
                                            <th>Rank</th>
                                            <th>Stock NO.</th>
                                            <th>Unit</th>
                                            <th>MIN</th>
                                            <th>MAX</th>
                                            <th>Remain</th>
                                            <th>OP</th>
                                            <th>Maker</th>
                                            <th>Price</th>
                                            <th>Status</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        <tr key={0}>
                                            {/* <td className="c">{part.code}</td>
                                            <td className="c">{part.name}</td> */}

                                            <td className="c">
                                                {typeof (part.date) === 'string' && dateFormat((new Date(part.date)), 'dd/mm/yyyy')}
                                            </td>
                                            <td className="c">{part.rank}</td>
                                            <td className="c">{part.locationCode}</td>
                                            <td className="c">{part.unit}</td>
                                            <td className="c">{part.minAmount}</td>
                                            <td className="c">{part.maxAmount}</td>
                                            <td className="c">{part.currentAmount}</td>
                                            <td className="c">{part.OP}</td>
                                            <td className="c">
                                                {part.vendorName}
                                            </td>
                                            <td className="c">{part.latestPrice}</td>
                                            <td className="c">
                                                <IconContext.Provider value={{ size: "2em" }}>
                                                    <div>
                                                        {part.currentAmount < part.OP && <FaTired style={{ color: 'red' }} />}
                                                        {part.currentAmount === part.OP && <FaMeh style={{ color: 'yellow' }} />}
                                                        {part.currentAmount > part.OP && <FaSmileBeam style={{ color: 'green' }} />}
                                                    </div>
                                                </IconContext.Provider>
                                            </td>

                                        </tr>
                                    </tbody>
                                </Table>

                                <Form.Group as={Row} controlId="date">
                                    <Col xs={2}>
                                        <Form.Label>วันที่</Form.Label>
                                    </Col>
                                    <Col>
                                        <DatePicker
                                            format="dd/MM/y"
                                            onChange={(date) => this.setState({ date })}
                                            value={this.state.date}
                                        />
                                    </Col>
                                </Form.Group>



                                <Form.Group as={Row} controlId="amount">
                                    <Col xs={2}>
                                        <Form.Label>จำนวนที่นำเข้า ({part.unit})</Form.Label>
                                    </Col>
                                    <Col>
                                        <Form.Control type="number" placeholder="จำนวนที่นำเข้า"
                                            value={this.state.amount}
                                            min={1}
                                            onChange={this.changeHandler}
                                            disabled={this.state.buttonDisabled}
                                        />
                                    </Col>
                                </Form.Group>

                                <Form.Group as={Row} controlId="price">
                                    <Col xs={2}>
                                        <Form.Label>ราคาต่อหน่วย</Form.Label>

                                    </Col>
                                    <Col>
                                        <Form.Control type="number" placeholder="ราคาต่อหน่วย"
                                            value={this.state.price}
                                            min={0}
                                            step="0.01"
                                            onChange={this.changeHandler}
                                            disabled={this.state.buttonDisabled}
                                        />
                                    </Col>
                                </Form.Group>

                                <Form.Group as={Row} controlId="vendor">
                                    <Col xs={2}>
                                        <Form.Label>MAKER</Form.Label>
                                    </Col>
                                    <Col>
                                        <VendorDropdown
                                            preselectVendorId={this.state.vendorId}
                                            selectHandler={this.selectVendorHandler}
                                            disabled={this.state.buttonDisabled}
                                        />
                                    </Col>
                                </Form.Group>

                                <div className="d-flex flex-column">
                                    <ButtonGroup >
                                        <Button variant="success" type="submit" disabled={this.state.buttonDisabled}>บันทึก</Button>
                                        {/* <Button variant="outline-secondary" onClick={this.props.closeFormHandler}>ยกเลิก</Button> */}
                                    </ButtonGroup>
                                </div>

                                {/* {this.state.transactions && */}
                                {this.state.part &&
                                    <PartHistory
                                        part={this.state.part}
                                        limit={10}
                                    // transactions={this.state.transactions}
                                    />
                                }
                            </>
                        }

                    </Form>
                </Container>
            </>
        );
    }
}

StockIn.contextType = UserContext;