import React from 'react';
import {
    Container,
    Row, Col,
    Modal,
    Button,
    // Table, Pagination, FormControl, InputGroup, ButtonGroup,
} from 'react-bootstrap';

import UserForm from './UserForm';
import UserPasswordForm from './UserPasswordForm';

import ReactDataGrid from "react-data-grid";
import {
    Menu, Data, Filters, Toolbar, 
    // ToolsPanel 
} from "react-data-grid-addons";

import {
    FaTrash, FaEdit,
    FaPlus, FaKey,
    // FaTimes, 
    // FaPhoneSquare, FaFax, FaRegEnvelope, 
    // FaAngleLeft, FaAngleRight
} from 'react-icons/fa';

import "./report-styles.css";

// const config = require('./config.js');
const apiUrl = process.env.REACT_APP_API_URL;

const { 
    ContextMenu, MenuItem, 
    ContextMenuTrigger,
    // SubMenu, 
} = Menu;
const {
    AutoCompleteFilter,
    MultiSelectFilter,
    // NumericFilter,
    // SingleSelectFilter
} = Filters;

export default class User extends React.Component {
    abortController = new AbortController();
    defaultColumnProperties = {
        filterable: false,
        sortable: true,
        // width: 120
    };
    selectors = Data.Selectors;

    columns = [
        { key: "code", name: "Code", sortDescendingFirst: true, filterable: true, filterRenderer: AutoCompleteFilter },
        { key: "name", name: "Name", width: 200, filterable: true, filterRenderer: AutoCompleteFilter },
        { key: "unit", name: "Unit/Div", filterable: true, filterRenderer: MultiSelectFilter, cellClass: 'center', width: 100 },
        { key: "email", name: "Email", filterable: true, filterRenderer: MultiSelectFilter, width: 200 },
        { key: "tel1", name: "Tel 1", filterable: true, filterRenderer: MultiSelectFilter, cellClass: 'center' },
        { key: "tel2", name: "Tel 2", filterable: true, filterRenderer: MultiSelectFilter, cellClass: 'center' },
    ];

    constructor(...args) {
        super(...args);

        let defaultColumnProperties = this.defaultColumnProperties;
        this.columns = this.columns.map(c => ({ ...defaultColumnProperties, ...c }));

        this.state = {
            q: '',
            user: null,
            users: [],
            activePage: 1,
            totalPages: 1,
            totalUsers: 0,
            itemsPerPage: 20,
            showMessageModal: false,
            messag: '',
            showDetail: false,
            showChangePassword: false,
            showEdit: false,
            showDeleteConfirm: false,
            newRecord: false
        }
    }

    UNSAFE_componentWillMount() {
        this.fetchTotalUsers();
        this.fetchUsers();
    }

    fetchTotalUsers() {
        fetch(apiUrl + 'user/count', {
            method: 'GET',
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            }
        })
            .then(response => response.json())
            .then(response => {
                // console.log('Success:', JSON.stringify(response));
                this.setState({
                    totalUsers: response.data,
                    totalPages: parseInt(response.data) / this.state.itemsPerPage
                });
            })
            .catch(error => {
                console.error('Error:', error);
            });
    }

    fetchUsers(q = '', page = 1) {

        let skip = (page - 1) * this.state.itemsPerPage;
        let limit = this.state.itemsPerPage;

        console.debug("fetchUsers", skip, limit);
        let url;
        if (q !== '' && q !== null) {
            url = apiUrl + 'user/search/' + q;
        } else {
            url = apiUrl + 'user?skip=' + skip + '&limit=' + limit;
        }

        fetch(url,
            {
                // fetch(apiUrl + 'user', {
                method: 'GET',
                params: { skip: skip, limit: limit },
                headers: {
                    'Accept': 'application/json',
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                }
            })
            .then(response => response.json())
            .then(jsonData => {
                // console.log(JSON.stringify(jsonData));
                this.setState({
                    users: jsonData.data,
                    activePage: page
                });
            })
            .catch(error => {
                console.error('Error:', error);
            });
    }

    handlePrevPage = () => {
        let activePage = parseInt(this.state.activePage);
        if (activePage === 0) return;
        // console.log('Prev Page:', activePage);
        this.fetchUsers(activePage - 1);
    }

    handleNextPage = () => {
        let activePage = parseInt(this.state.activePage);
        if (activePage === this.state.totalPages) return;
        // console.log('Next Page:', activePage);
        this.fetchUsers(activePage + 1);
    }

    editHandler = (rowInx) => {
        this.showDetail(this.state.users[rowInx])
    }

    changePasswordHandler = (rowInx) => {
        this.changePassword(this.state.users[rowInx])
    }

    userToDelete = {};
    confirmDelete = (user) => {
        this.userToDelete = user;
        this.setState({
            showDeleteConfirm: true
        })
    }

    deleteHandler = (id) => {
        console.log(id);
        this.setState({ showDeleteConfirm: false },
            () => fetch(apiUrl + 'user', {
                method: 'DELETE',
                headers: {
                    'Accept': 'application/json',
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                body: JSON.stringify({ id: id })
            })
                .then(response => response.json())
                .then(response => {
                    console.log('Delete Success:', JSON.stringify(response));
                    this.setState({
                        modalShowResult: true,
                        message: 'ลบข้อมูลผู้ใช้งาน แล้ว'
                    },
                        () => this.fetchUsers()
                    );
                })
                .catch(error => {
                    console.error('Error:', error);
                })
        );
    }


    showDetail = (v) => {
        // console.log(v);
        this.setState({
            showDetail: true,
            user: v
        });
    }



    closeDetail = (reload = true, afterCloseMessage = '') => {
        if (reload) {
            this.fetchUsers();
        }
        this.setState({
            showDetail: false,
            newRecord: false
        },
            () => {
                if (afterCloseMessage !== '') {
                    this.setState({
                        showMessageModal: true,
                        message: afterCloseMessage
                    });
                }
            });
    }

    changePassword = (v) => {
        this.setState({
            showChangePassword: true,
            user: v
        });
    }

    closeChangePassword = (reload = true, afterCloseMessage = '') => {
        if (reload) {
            this.fetchUsers();
        }
        this.setState({
            showDetail: false,
            showChangePassword: false
        },
            () => {
                if (afterCloseMessage !== '') {
                    this.setState({
                        showMessageModal: true,
                        message: afterCloseMessage
                    });
                }
            });
    }

    addHandler = () => {
        this.setState({
            showDetail: true,
            newRecord: true
        });
    }

    searchChangeHandler = (e) => {
        this.setState({ q: e.target.value });
    }

    clearSearch = (e) => {
        let _this = this;
        this.setState(
            { q: '' },
            () => {
                _this.searchUsers();
            }
        );

    }

    searchUsers = () => {
        let q = this.state.q;
        console.log("Searching ", q);
        this.fetchUsers(q);
    }

    handleFilterChange = filter => {
        let filters = this.state.filters;
        const newFilters = { ...filters };
        if (filter.filterTerm) {
            newFilters[filter.column.key] = filter;
        } else {
            delete newFilters[filter.column.key];
        }
        return newFilters;
    };

    getValidFilterValues = (rows, columnId) => {
        return rows
            .map(r => r[columnId])
            .filter((item, i, a) => {
                return i === a.indexOf(item);
            });
    }


    getRows = (rows, filters) => {
        // console.log('filters', filters)
        return this.selectors.getRows({ rows, filters });
    }

    sortRows = (initialRows, sortColumn, sortDirection) => {
        console.log("sortRows")
        let rows = this.state.users;
        const comparer = (a, b) => {
            if (sortDirection === "ASC") {
                return a[sortColumn] > b[sortColumn] ? 1 : -1;
            } else if (sortDirection === "DESC") {
                return a[sortColumn] < b[sortColumn] ? 1 : -1;
            }
        };
        return sortDirection === "NONE" ? initialRows : [...rows].sort(comparer);
    }

    render() {
        let filteredRows = this.getRows(this.state.users, this.state.filters);

        // const list = this.state.users.map((v, i) => {

        //     return (
        //         <tr key={i}>
        //             <td>
        //                 <FaEdit onClick={(e) => this.showDetail(v)} />
        //                 <FaKey onClick={(e) => this.changePassword(v)} />
        //                 <FaTrash onClick={(e) => this.confirmDelete(v)} />
        //             </td>
        //             <td>
        //                 <a onClick={(e) => this.showDetail(v)}>
        //                     {v.code}
        //                 </a>
        //             </td>
        //             <td>
        //                 <a onClick={(e) => this.showDetail(v)}>
        //                     {v.name}
        //                 </a><br />
        //                 {v.type}
        //             </td>
        //             <td>
        //                 {v.unit}/{v.division}
        //             </td>
        //             <td>
        //                 {v.tel1} {v.tel2}
        //             </td>
        //             <td>
        //                 {v.email}
        //             </td>
        //         </tr>
        //     )
        // });

        // let activePage = this.state.activePage;
        // let totalPages = this.state.totalPages;
        // let paginationItems = [];
        // paginationItems.push(
        //     <Pagination.Item key={0} disabled={1 === activePage} onClick={this.handlePrevPage}>
        //         หน้าแรก
        //     </Pagination.Item>
        // );
        // paginationItems.push(
        //     <Pagination.Item key={-1} disabled={this.state.totalPages === activePage} onClick={this.handleNextPage}>
        //         หน้าถัดไป
        //     </Pagination.Item>
        // );
        // for (let number = 1; number <= totalPages; number++) {
        //     paginationItems.push(
        //         <Pagination.Item key={number} active={number === activePage}>
        //             {number}
        //         </Pagination.Item>
        //     );
        // }
        // "code": 2101082,
        // "name": "ณรงค์ชัย  เกษตรวรรณกุล",
        // "address": "700/309 ม.6 ต.ดอนหัวฬ่อ อ.เมือง จ.ชลบุรี 20000",
        // "tel1": "038-214805-6",
        // "tel2": "086-0402413",
        // "unit": "ME",
        // "division": "MT",
        // "note": "",  
        return (
            <>
                <Container fluid>
                    <Row>
                        <Col>
                            <h2>ผู้ใช้งาน ({this.state.totalUsers})</h2>
                        </Col>
                        <Col sm={4} style={{ textAlign: 'right' }}>
                            <Button variant="success" onClick={this.addHandler}>
                                <FaPlus /> เพิ่มผู้ใช้งาน
                        </Button>
                        </Col>
                    </Row>

                    {/* <Row>
                        <Col>
                            <InputGroup className="mb-3">
                                <FormControl
                                    placeholder="ค้นหาด้วยชื่อ"
                                    aria-label="ค้นหาด้วยชื่อ"
                                    aria-describedby="basic-addon2"
                                    value={this.state.q}
                                    onChange={this.searchChangeHandler}
                                    onKeyPress={event => {
                                        if (event.key === "Enter") {
                                            this.searchUsers();
                                        }
                                    }}
                                />
                                <InputGroup.Append>
                                    <Button variant="outline-secondary"
                                        onClick={this.searchUsers}>
                                        ค้นหา
                                </Button>
                                    <Button variant="outline-secondary"
                                        onClick={this.clearSearch}>
                                        <FaTimes />
                                    </Button>
                                </InputGroup.Append>
                            </InputGroup>

                        </Col>
                    </Row> */}

                    <ReactDataGrid
                        columns={this.columns}
                        rowGetter={i => filteredRows[i]}
                        rowsCount={filteredRows.length}
                        // minWidth={1024}
                        minHeight={500}
                        contextMenu={
                            <DataContextMenu
                                onRowEdit={(e, { rowIdx }) => this.editHandler(rowIdx)}
                                onRowChangePassword={(e, { rowIdx }) => this.changePasswordHandler(rowIdx)}
                                onRowDelete={(e, { rowIdx }) => this.setState({ rows: this.confirmDelete(rowIdx) })}
                            />
                        }
                        onGridSort={(sortColumn, sortDirection) =>
                            this.setState({
                                users: this.sortRows(this.state.users, sortColumn, sortDirection)
                            })
                        }
                        RowsContainer={ContextMenuTrigger}
                        emptyRowsView={this.EmptyRowsView}
                        toolbar={
                            <Toolbar enableFilter={true}>
                                {/* <ButtonGroup aria-label="Basic example">
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(0)}>
                                        View All
                                </Button>
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(1)}>
                                        A
                                    </Button>
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(2)}>
                                        B
                                    </Button>
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(3)}>
                                        C
                                    </Button>
                                </ButtonGroup> */}
                            </Toolbar>
                        }
                        onAddFilter={filter => this.setState({ filters: this.handleFilterChange(filter) })}
                        onClearFilters={() => this.setState({ filters: {} })}
                        getValidFilterValues={columnKey => this.getValidFilterValues(this.state.users, columnKey)}

                    />
                    {/* 
                    <Pagination size="sm">{paginationItems}</Pagination>
                    <Table striped bordered hover size="sm">
                        <thead>
                            <tr>
                                <th>#</th>
                                <th>Code</th>
                                <th>Name</th>
                                <th>Unit/Div</th>
                                <th>Tel</th>
                                <th>Email</th>

                            </tr>
                        </thead>
                        <tbody>
                            {list}
                        </tbody>
                    </Table> */}
                </Container>

                <Modal
                    size="lg"
                    aria-labelledby="contained-modal-title-vcenter"
                    centered
                    show={this.state.showDetail}
                    onHide={this.closeDetail}
                >
                    <Modal.Header closeButton>
                        <Modal.Title id="contained-modal-title-vcenter">
                            รายละเอียดผู้ใช้งาน
                    </Modal.Title>
                    </Modal.Header>
                    <Modal.Body>
                        <UserForm
                            newRecord={this.state.newRecord}
                            closeFormHandler={this.closeDetail}
                            data={this.state.user}
                        />
                    </Modal.Body>
                    {/* <Modal.Footer>
                        <Button onClick={()=>this.setState({modalShow:false})}>Close</Button>
                    </Modal.Footer> */}
                </Modal>

                <Modal
                    size="lg"
                    aria-labelledby="contained-modal-title-vcenter"
                    centered
                    show={this.state.showChangePassword}
                    onHide={this.closeChangePassword}
                >
                    <Modal.Header closeButton>
                        <Modal.Title id="contained-modal-title-vcenter">
                            เปลี่ยนรหัสผ่าน
                    </Modal.Title>
                    </Modal.Header>
                    <Modal.Body>
                        <UserPasswordForm
                            closeFormHandler={this.closeChangePassword}
                            user={this.state.user}
                        />
                    </Modal.Body>
                </Modal>

                <Modal
                    size="lg"
                    aria-labelledby="contained-modal-title-vcenter"
                    centered
                    show={this.state.showDeleteConfirm}
                    onHide={() => this.setState({ showDeleteConfirm: false })}
                >

                    <Modal.Body>
                        ยืนยันลบข้อมูล {this.userToDelete.name}
                    </Modal.Body>
                    <Modal.Footer>
                        <Button variant="danger" onClick={() => this.deleteHandler(this.userToDelete._id)}>ลบ</Button>
                        <Button variant="outline-secondary" onClick={() => this.setState({ showDeleteConfirm: false })}>ยกเลิก</Button>
                    </Modal.Footer>
                </Modal>

                <Modal
                    size="lg"
                    aria-labelledby="contained-modal-title-vcenter"
                    centered
                    show={this.state.showMessageModal}
                    onHide={() => this.setState({ showMessageModal: false })}
                >
                    <Modal.Body>
                        {this.state.message}
                    </Modal.Body>
                    <Modal.Footer>
                        <Button variant="outline-secondary" onClick={() => this.setState({ showMessageModal: false })}>
                            ปิด
                            </Button>
                    </Modal.Footer>
                </Modal>
            </>
        );
    }
}

function DataContextMenu({
    idx,
    id,
    rowIdx,
    onRowDelete,
    onRowEdit,
    onRowChangePassword
}) {
    return (
        <ContextMenu id={id} style={{ backgroundColor: 'white', width: '200px' }}>
            {/* <MenuItem data={{ rowIdx, idx }} onClick={onRowAdd}><FaPlus /> เพิ่มวัสดุ / อะไหล่</MenuItem> */}
            <MenuItem data={{ rowIdx, idx }} onClick={onRowEdit}><FaEdit /> แก้ไข</MenuItem>
            <MenuItem data={{ rowIdx, idx }} onClick={onRowChangePassword}><FaKey /> เปลี่ยนรหัสผ่าน</MenuItem>
            <MenuItem data={{ rowIdx, idx }} onClick={onRowDelete}><FaTrash /> ลบ</MenuItem>
        </ContextMenu>
    );
}