import React from 'react';
import {
    Col,
    Form,
    Button, ButtonGroup,
    // Row, Container, Table, Pagination, InputGroup, FormControl, Modal
} from 'react-bootstrap';

// const config = require('./config.js');
const apiUrl = process.env.REACT_APP_API_URL;

export default class VendorForm extends React.Component {
    constructor(...args) {
        super(...args);
        if (this.props.data && this.props.data.name) {
            this.state = this.props.data;
            console.log(this.state)
            if (this.state.prefOrder === null) {
                this.state.prefOrder = 0;
            }
        } else {
            this.state = {
                code: 'a',
                prefOrder: 0,
                name: 'aaaaa',
                address: 'a',
                details: 'a',
                tel: 'a',
                fax: 'a',
                phone: 'a',
                email: 'a@a.com',
                contactPerson: 'a'
            }
        }
    }
    changeHandler = (e) => {

        this.setState({
            [e.target.id]: e.target.value
        })
    }

    submitHandler = event => {
        const form = event.currentTarget;
        event.preventDefault();
        if (form.checkValidity() === false) {
            event.stopPropagation();
        }
        console.log(this.state);
        let vendor = this.state;

        fetch(apiUrl + 'vendors', {
            method: 'POST',
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            body: JSON.stringify(vendor)
        })
            .then(response => response.json())
            .then(response => {
                console.log('Success:', JSON.stringify(response));
                this.props.closeFormHandler(true);
            })
            .catch(error => {
                this.props.closeFormHandler(false);
                console.error('Error:', error);
            });

    };

    render() {
        return (
            <Form onSubmit={this.submitHandler}>
                <Form.Row>
                    <Form.Group as={Col} controlId="code">
                        <Form.Label>ทะเบียนผู้ขาย</Form.Label>
                        <Form.Control type="text" placeholder="ทะเบียนผู้ขาย"
                            value={this.state.code}
                            onChange={this.changeHandler} />
                    </Form.Group>

                    <Form.Group as={Col} controlId="prefOrder">
                        <Form.Label>ลำดับเลือกซื้อ</Form.Label>
                        <Form.Control type="number" placeholder="ลำดับเลือกซื้อ"
                            value={this.state.prefOrder}
                            onChange={this.changeHandler} />
                    </Form.Group>
                </Form.Row>

                <Form.Group controlId="name">
                    <Form.Label>ชื่อผู้ขาย</Form.Label>
                    <Form.Control placeholder="ชื่อผู้ขาย"
                        value={this.state.name}
                        onChange={this.changeHandler} />
                </Form.Group>

                <Form.Group controlId="address">
                    <Form.Label>ที่อยู่</Form.Label>
                    <Form.Control placeholder="ที่อยู่"
                        value={this.state.address}
                        onChange={this.changeHandler} />

                </Form.Group>

                <Form.Group controlId="details">
                    <Form.Label>รายละเอียดผู้ขาย</Form.Label>
                    <Form.Control placeholder="รายละเอียดผู้ขาย"
                        value={this.state.details}
                        onChange={this.changeHandler} />
                </Form.Group>

                <Form.Group controlId="phone">
                    <Form.Label>โทร.</Form.Label>
                    <Form.Control placeholder="โทร."
                        value={this.state.phone}
                        onChange={this.changeHandler} />
                </Form.Group>
                <Form.Row>
                    <Form.Group controlId="tel">
                        <Form.Label>โทร.มือถือ</Form.Label>
                        <Form.Control placeholder="โทร.มือถือ"
                            value={this.state.tel}
                            onChange={this.changeHandler} />
                    </Form.Group>

                    <Form.Group controlId="fax">
                        <Form.Label>FAX</Form.Label>
                        <Form.Control placeholder="FAX"
                            value={this.state.fax}
                            onChange={this.changeHandler} />
                    </Form.Group>
                </Form.Row>

                <Form.Group controlId="email">
                    <Form.Label>e-mail</Form.Label>
                    <Form.Control placeholder="e-mail"
                        value={this.state.email}
                        onChange={this.changeHandler} />
                </Form.Group>
                <Form.Group controlId="contactPerson">
                    <Form.Label>ผู้ประสานงาน</Form.Label>
                    <Form.Control placeholder="ผู้ประสานงาน"
                        value={this.state.contactPerson}
                        onChange={this.changeHandler} />
                </Form.Group>
                <div className="d-flex flex-column">
                    <ButtonGroup >
                        <Button variant="success" type="submit">
                            บันทึก
                </Button>
                        <Button variant="outline-secondary"
                            onClick={this.props.closeFormHandler}>
                            ยกเลิก
                </Button>
                    </ButtonGroup>
                </div>
            </Form>
        );
    }
}
