import React from 'react';
import {
    Container, Table,
    // Pagination, Button, Modal, Row, Col, FormControl, InputGroup, ButtonGroup,
} from 'react-bootstrap';


import "./report-styles.css";

import { DataContext } from './data-context.js';

const dateFormat = require('dateformat');
// const config = require('./config.js');
// const apiUrl = process.env.REACT_APP_API_URL;
const util = require('./util.js');

export default class PartHistory extends React.Component {
    static contextType = DataContext;
    data = {};
    vendors = [];
    vendorMap = {};

    users = [];
    userMap = {};
    limit = 0;

    constructor(...args) {
        super(...args);
        // console.log('this.props.transactions',this.props.transactions);
        this.state = {
            part: this.props.part,
            // transactions: this.props.transactions
        }
        this.limit = (this.props.limit) ? this.props.limit : 0;
        this.data = this.context;
        this.vendors = this.data.vendors;
        this.users = this.data.users;

        // Convert vendors list to map
        this.vendors.forEach(v => {
            this.vendorMap[v._id] = v;
        })

        this.users.forEach(v => {
            this.userMap[v._id] = v;
        })

        // console.log('PartHistory VendorMap', this.vendorMap);
        console.log('PartHistory UserMap', this.userMap);
        this.fetchTransactions();
    }

    UNSAFE_componentWillReceiveProps() {
        // UNSAFE_componentWillUpdate() {
        // let thisClass = this;
        // this.fetchUsers();
        console.log('UNSAFE_componentWillReceiveProps fetchTransactions')
        this.fetchTransactions();
    }

    fetchTransactions() {
        util.fetchTransactions(this.state.part._id,
            (res) => {
                console.log('fetchTransaction', res);
                this.setState({
                    transactions: res.data
                });
            },
            (err) => {
                console.error(err);
            }, this.limit);
    }



    render() {
        // let part = this.props.part;
        // let users = this.state.users;
        // console.log('part', part)

        if (!this.state.transactions)
            return (<></>);

        let transactions = this.state.transactions.map((v, i) => {
            // let displayDate = dateFormat(v.createdAt, 'dd/mm/yyyy HH:MM')
            let displayDate = dateFormat(v.date, 'dd/mm/yyyy HH:MM')
            let user = this.userMap[v.user];
            let userName = user === undefined ? '-' : user.name;
            // console.log('user', v.user, user)
            let debit = v.amount > 0 ? v.amount : '-';
            let credit = v.amount < 0 ? -v.amount : '-';

            let vendor = this.vendorMap[v.vendor];
            if (v.amount < 0) {
                v.vendorName = '-';
                v.price = '-';
            } else if (vendor) {
                v.vendorName = vendor.name;
            } else {
                v.vendorName = v.vendor;
            }
            // console.log(vendor)

            return (
                <tr key={i}>
                    <td className="c">{displayDate}</td>
                    <td className="c">{userName}</td>
                    {/* <td className="r">{v.original}</td> */}
                    <td className="c">{debit}</td>
                    <td className="c">{credit}</td>
                    {/* <td className="r">{v.adjusted}</td> */}
                    <td className="c">{v.price}</td>
                    <td className="c">{v.vendorName}</td>
                </tr>
            )
        });

        return (
            <Container>
                {/* <h3>{part.code} : {part.name}</h3> */}
                <Table id="table-history" striped bordered hover size="sm">
                    <thead>
                        <tr>
                            <th>Date/Time</th>
                            <th>User</th>
                            {/* <th>ยกมา</th> */}
                            <th>เพิ่ม</th>
                            <th>ลด</th>
                            {/* <th>คงเหลือ</th> */}
                            <th>ราคา</th>
                            <th>MAKER</th>
                        </tr>
                    </thead>
                    <tbody>
                        {transactions}
                    </tbody>
                </Table>
            </Container>
        )
    }
}

