import React from 'react';
import {
    Container
} from 'react-bootstrap';


export default function Help(props) {
    return (
        <Container>
            <h2>Help</h2>
            <ul>
                <li><a rel="noopener noreferrer" target="_blank" href={process.env.REACT_APP_MANUAL_URL}>Download Manual</a></li>
            </ul>
        </Container>
    );
}
