import React, { useState, useEffect } from 'react';

import {
    Form, Dropdown
} from 'react-bootstrap';

// const config = require('./config.js');
const apiUrl = process.env.REACT_APP_API_URL;

class CustomMenu extends React.Component {
    constructor(props, context) {
        super(props, context);
        this.state = { searchKey: '' };
    }

    handleChange = (e) => {
        // console.log("ITEM", e.target.value.toLowerCase().trim());
        this.setState({ searchKey: e.target.value.toLowerCase().trim() });
    }

    render() {
        const {
            children,
            style,
            className,
            'aria-labelledby': labeledBy,
        } = this.props;

        const { searchKey: value } = this.state;

        return (
            <div
                style={style} className={className}
                aria-labelledby={labeledBy}
            >
                <Form.Control
                    autoFocus
                    // className="mx-3 my-2 w-auto"
                    placeholder="เลือกผู้ขาย..."
                    onChange={this.handleChange}
                    value={value}
                />
                <ul className="list-unstyled">
                    {React.Children.toArray(children).filter(
                        child =>
                            !value || child.props.children.toLowerCase().includes(value),
                    )}
                </ul>
            </div>
        );
    }
}



function VendorDropdown(props) {
    const [vendorMap, setVendorMap] = useState({});

    const fetchVendors = () => {
        fetch(apiUrl + 'vendor?skip=0&limit=0', {
            method: 'GET',
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            }
        })
            .then(response => response.json())
            .then(jsonData => {
                // make a dict for vendors
                let vendors = {};
                for (let i = 0; i < jsonData.data.length; i++) {
                    let item = jsonData.data[i];
                    vendors[item._id] = item;
                    // console.log(i)
                }


                setVendorMap(vendors)

            })
            .catch(error => {
                console.error('Error:', error);
            });
    }

    useEffect(() => fetchVendors(), []); // that [] indicates the fetchVendors() runs only when the componentDidMount()

    let vendorArray = Object.values(vendorMap); // Dict to Array        
    const vendorList = vendorArray.map((v) => {
        // console.log('dropdown item',project);
        return (
            <Dropdown.Item
                key={v._id}
                eventKey={v._id}                
            >
                {v.name}
            </Dropdown.Item>
        );
    })

    // console.log('props.vendor', props.vendor)
    // console.log('preselectVendorId', props.preselectVendorId);
    let vendorId = props.preselectVendorId
    let vendor = vendorMap[vendorId]
    vendor = vendor === undefined ? { _id: '', name: '' } : vendor;
    // console.log('vendorMap', vendorMap)
    // console.log('vendor', vendor)

    if (props.disabled) {
        return (<>{vendor.name}</>);
    } else {
        // console.log('VendorDropdown',props.required)
        return (
            <Dropdown
                onSelect={props.selectHandler}
                name="vendor"
            >
                <Dropdown.Toggle variant="outline-dark" id="dropdown-custom-components">
                    {true} {vendor.name}
                </Dropdown.Toggle>

                <Dropdown.Menu as={CustomMenu}>
                    {vendorList}
                </Dropdown.Menu>
            </Dropdown>

        );
    }
}
export default VendorDropdown;
