import React from 'react';
import {
  // Container, Row, Col,
  Nav, Navbar, NavDropdown
} from 'react-bootstrap';

// import logo from './logo.svg';
import LogIn from './LogIn';
import Home from './Home';
import Store from './Store';
import packageJson from '../package.json';
import Part from './Part';
import PartGroup from './PartGroup';
import Vendor from './Vendor';
import User from './User';
import UserProfile from './UserProfile';
import StockOut from './StockOut';
import StockIn from './StockIn';
import Help from './Help';
import { UserContext } from './user-context.js';
import { DataContext } from './data-context.js';

// const config = require('./config.js');
const apiUrl = process.env.REACT_APP_API_URL;
const util = require('./util.js');

export default class App extends React.Component {
  constructor(...args) {
    super(...args);


    if (process.env.NODE_ENV === 'production') {
      this.state = {
        data: {}, // data-context
        tab: '#home',
        user: null,  // PROD
      }

    } else {
      let demoUser = {
        _id: "5da1387fe58eb52ac31e0ee2",
        code: "3299029",
        address: "700/309 หมู่ 6 ต.ดอนหัวฬ่อ อ. เมื่อง จ.ชลบุรี",
        division: "MT",
        email: "",
        name: "วิไล แก้วไกรเพชร์",
        note: "",
        tel1: "172",
        tel2: "086-1509040",
        unit: "ME",
        isAdmin: true
      };

      let defaultTab = demoUser.isAdmin ? '#action/1.1' : '#home';
      // defaultTab = '#stock/out';

      this.state = {
        data: {}, // data-context
        tab: defaultTab,
        user: demoUser,
      }
    }

    console.log(`[${process.env.NODE_ENV}]`)
    console.log(`[${process.env.REACT_APP_MANUAL_URL}]`)
    console.log("React Version:", React.version);    
    console.log("API EndPoint:", apiUrl);
    // console.log("Demo User", this.state.user);
  }

  UNSAFE_componentWillMount() {
    // console.log("App util.fetchVendors");
    util.fetchVendors(
      (res) => {
        let data = this.state.data;
        data['vendors'] = res.data;
        this.setState({
          data: data
        })
      },
      (err) => {
        console.error(err);
      }
    );

    util.fetchUsers(
      (res) => {
        let data = this.state.data;
        data['users'] = res.data;
        this.setState({
          data: data
        })
      },
      (err) => {
        console.error(err);
      }
    );
  }

  handleNavSelect = (k, e) => {
    console.log(k);
    // console.log(process.env.REACT_MANUAL_URL);
    if (k === '#logout') {
      this.handleLogOut();
      return;
    }
    this.setState({ tab: k });
  }

  handleLoginSuccess = (user) => {
    console.log("handleSuccessLogIn", user);
    let defaultTab = user.isAdmin ? '#action/1.1' : '#home';
    this.setState({
      user: user,
      tab: defaultTab
    });
  }

  handleLoginFailure = (err) => {
    // console.log("handleSuccessLogIn", user);
    alert(err.message);
  }

  handleLogOut = () => {
    fetch(apiUrl + 'user/logout', {
      method: 'GET',
      headers: {
        'Accept': 'application/json',
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': '*'
      }
    })
      .then(response => response.json())
      .then(response => {
        console.log('Success:', JSON.stringify(response));
      })
      .catch(error => {
        console.error('Error:', error);
      });

    this.setState({
      user: null,
      tab: '#home'
    });
  }

  render() {
    // console.log(this.state.user);
    if (this.state.user === undefined || this.state.user === null) {
      return (
        <>
          <LogIn
            handleLoginSuccess={this.handleLoginSuccess}
            handleLoginFailure={this.handleLoginFailure}
          />
        </>
      )
    }

    let user = this.state.user;
    let data = this.state.data;
    // console.log("UserContext",UserContext.displayName,user)
    return (
      <>
        <DataContext.Provider value={data}>
          <UserContext.Provider value={user}>
            <Navbar collapseOnSelect expand="lg" bg="dark" variant="dark" onSelect={this.handleNavSelect}>
              <Navbar.Brand href="#home">SPM</Navbar.Brand>
              <Navbar.Toggle aria-controls="responsive-navbar-nav" />
              <Navbar.Collapse id="responsive-navbar-nav">
                <Nav className="mr-auto">
                  {/* <Nav.Link href="#dashboard">Dashboard</Nav.Link> */}
                  <Nav.Link href="#home">Home</Nav.Link>
                  {this.state.user.isAdmin && <Nav.Link href="#action/1.1">วัสดุ/อะไหล่</Nav.Link>}
                  {/* <NavDropdown title="วัสดุ/อะไหล่" id="collasible-nav-dropdown">
                  <NavDropdown.Item href="#action/1.1">ทะเบียน</NavDropdown.Item>
                  <NavDropdown.Item href="#action/1.2">กลุ่ม</NavDropdown.Item>
                  <NavDropdown.Item href="#action/1.3">คลัง</NavDropdown.Item>
                </NavDropdown> */}
                  {this.state.user.isAdmin && <Nav.Link href="#action/2.1">ผู้จัดจำหน่าย</Nav.Link>}
                  {this.state.user.isAdmin && <Nav.Link href="#action/3.1">พนักงาน</Nav.Link>}
                  {/* <NavDropdown title="ผู้จัดจำหน่าย" id="collasible-nav-dropdown" >
                <NavDropdown.Item href="#action/2.1">ผู้จัดจำหน่าย</NavDropdown.Item>
                <NavDropdown.Item href="#action/2.2">รายงาน ?</NavDropdown.Item>
              </NavDropdown> */}
                  {/* <NavDropdown title="พนักงาน" id="collasible-nav-dropdown">
                <NavDropdown.Item href="#action/3.1">พนักงาน</NavDropdown.Item>
                <NavDropdown.Item href="#action/3.2">รายงาน ?</NavDropdown.Item>
              </NavDropdown> */}
                  {/* <NavDropdown title="คลัง" id="collasible-nav-dropdown">
                <NavDropdown.Item href="#action/4.1">คลัง</NavDropdown.Item>
                <NavDropdown.Item href="#action/4.2">รายงาน ?</NavDropdown.Item>
              </NavDropdown> */}
                </Nav>
                <Nav>
                  <NavDropdown title={user.name} id="collasible-nav-dropdown">
                    <NavDropdown.Item href="#action/5.1">ประวัติ</NavDropdown.Item>
                    <NavDropdown.Divider />
                    <NavDropdown.Item href="#logout">Log Out</NavDropdown.Item>
                  </NavDropdown>
                </Nav>
                <Nav.Link href="#help">
                  Help
          </Nav.Link>
          <span style={{color: '#a0a0a0'}}>Version: {packageJson.version}-{process.env.NODE_ENV}</span>
              </Navbar.Collapse>
            </Navbar>
            {this.state.tab === '#home' && <Home setTab={(tab) => this.setState({ tab: tab })} />}
            {this.state.tab === '#store' && <Store />}
            {this.state.tab === '#action/1.1' && <Part />}
            {this.state.tab === '#action/1.2' && <PartGroup />}
            {this.state.tab === '#action/2.1' && <Vendor />}
            {this.state.tab === '#action/3.1' && <User />}
            {this.state.tab === '#action/5.1' && <UserProfile />}
            {this.state.tab === '#stock/out' && <StockOut />}
            {this.state.tab === '#stock/in' && <StockIn />}
            {this.state.tab === '#help' && <Help />}

          </UserContext.Provider>
        </DataContext.Provider>
      </>
    );
  }

}

