import React from 'react';
import PropTypes from 'prop-types';
import {
    Row, Col,
    Form, Container,
    Button,
    Modal,
    // Table,
    // Pagination, InputGroup, FormControl,
    // ButtonGroup,
} from 'react-bootstrap';
import { UserContext } from './user-context.js';
import UserPasswordForm from './UserPasswordForm';

// const config = require('./config.js');
// const apiUrl = process.env.REACT_APP_API_URL;


export default class UserProfile extends React.Component {

    constructor(...args) {
        super(...args);
        console.log('context', this.context);
        this.state = {
            ...this.context,
            showChangePassword: false,
        }
    }

    changeHandler = (e) => {
        return;
        // READ ONLY
        // this.setState({
        //     [e.target.id]: e.target.value
        // })
    }


    changePassword = () => {
        this.setState({
            showChangePassword: true
        });
    }

    closeChangePassword = (reload = true, afterCloseMessage = '') => {
        if (reload) {
            // this.fetchUsers();
            // Not needed in this class.
        }
        this.setState({
            showChangePassword: false
        },
            () => {
                if (afterCloseMessage !== '') {
                    this.setState({
                        showMessageModal: true,
                        message: afterCloseMessage
                    });
                }
            });
    }


    render() {
        return (
            <Container fluid>
                <Row>
                    <Col sm={12} style={{ textAlign: 'right' }}>
                        <Button onClick={this.changePassword}>เปลี่ยนรหัสผ่าน</Button>
                    </Col>
                </Row>

                <Modal
                    size="lg"
                    aria-labelledby="contained-modal-title-vcenter"
                    centered
                    show={this.state.showChangePassword}
                    onHide={this.closeChangePassword}
                >
                    <Modal.Header closeButton>
                        <Modal.Title id="contained-modal-title-vcenter">
                            เปลี่ยนรหัสผ่าน
                    </Modal.Title>
                    </Modal.Header>
                    <Modal.Body>
                        <UserPasswordForm
                            closeFormHandler={this.closeChangePassword}
                            user={this.context}
                        />
                    </Modal.Body>
                </Modal>


                <Form>
                    <Form.Row>
                        <Col xs={4}>
                            <Form.Group as={Col} controlId="code">
                                <Form.Label>หมายเลขประจำตัว</Form.Label>
                                <Form.Control type="text" placeholder="Code"
                                    value={this.state.code}
                                    onChange={this.changeHandler} />
                            </Form.Group>
                        </Col>
                        <Col xs={8}>
                            <Form.Group controlId="name">
                                <Form.Label>ชื่อ</Form.Label>
                                <Form.Control placeholder="ชื่อ"
                                    value={this.state.name}
                                    onChange={this.changeHandler} />
                            </Form.Group>
                        </Col>
                    </Form.Row>



                    <Form.Group controlId="address">
                        <Form.Label>ที่อยู่</Form.Label>
                        <Form.Control placeholder="ที่อยู่"
                            value={this.state.address}
                            onChange={this.changeHandler} />

                    </Form.Group>

                    <Form.Group controlId="note">
                        <Form.Label>รายละเอียด</Form.Label>
                        <Form.Control placeholder="รายละเอียด"
                            value={this.state.note}
                            onChange={this.changeHandler} />
                    </Form.Group>

                    <Form.Row>
                        <Col xs={6}>
                            <Form.Group controlId="unit">
                                <Form.Label>UNIT</Form.Label>
                                <Form.Control placeholder="UNIT"
                                    value={this.state.unit}
                                    onChange={this.changeHandler} />
                            </Form.Group>
                        </Col>
                        <Col xs={6}>
                            <Form.Group controlId="division">
                                <Form.Label>Division</Form.Label>
                                <Form.Control placeholder="Division"
                                    value={this.state.division}
                                    onChange={this.changeHandler} />
                            </Form.Group>
                        </Col>
                    </Form.Row>

                    <Form.Row>
                        <Col xs={6}>
                            <Form.Group controlId="tel1">
                                <Form.Label>โทร 1</Form.Label>
                                <Form.Control placeholder="โทร 1"
                                    value={this.state.tel1}
                                    onChange={this.changeHandler} />
                            </Form.Group>
                        </Col>
                        <Col xs={6}>
                            <Form.Group controlId="tel2">
                                <Form.Label>โทร 2</Form.Label>
                                <Form.Control placeholder="โทร 2"
                                    value={this.state.tel2}
                                    onChange={this.changeHandler} />
                            </Form.Group>
                        </Col>
                    </Form.Row>

                    {this.props.newRecord && <h3>ข้อมูลสำหรับเข้าระบบ</h3>}
                    <Form.Group controlId="email">
                        <Form.Label>e-mail</Form.Label>
                        <Form.Control placeholder="e-mail"
                            required
                            value={this.state.email}
                            onChange={this.changeHandler} />
                    </Form.Group>
                    {this.props.newRecord &&
                        <>
                            <Form.Group controlId="password">
                                <Form.Label>Password</Form.Label>
                                <Form.Control placeholder="Password"
                                    type="password"
                                    required
                                    value={this.state.password}
                                    onChange={this.changeHandler} />
                            </Form.Group>
                            {/* <Form.Group controlId="password2">
                            <Form.Label>ยืนยัน Password</Form.Label>
                            <Form.Control placeholder="ยืนยัน Password"
                                required
                                value={this.state.password2}
                                onChange={this.changeHandler} />
                        </Form.Group> */}
                        </>
                    }


                </Form>
            </Container>
        );
    }
}

UserProfile.contextType = UserContext;
UserProfile.propTypes = {
    newRecord: PropTypes.bool
};