    _handleKeyDown = (event) => {
        if (this.state.renderReportPage || this.state.showHistory) {
            switch (event.keyCode) {
                case 27:
                    this.setState({
                        renderReportPage: false,
                        showHistory: false
                    });
                    break;
                default:
                    break;
            }
        }
    }
    UNSAFE_componentWillMount() {
        this.fetchTotalParts();
        this.fetchParts();
        document.addEventListener("keydown", this._handleKeyDown);
    }

    componentWillUnmount() {
        this.abortController.abort();
        document.removeEventListener("keydown", this._handleKeyDown);
    }

    fetchTotalParts() {
        fetch(apiUrl + 'part/count', {
            method: 'GET',
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            }
        })
            .then(response => response.json())
            .then(jsonData => {
                // console.log('Success:', JSON.stringify(response));
                this.setState({
                    totalParts: jsonData.data,
                    totalPages: parseInt(jsonData.data) / this.state.itemsPerPage
                });
            })
            .catch(error => {
                console.error('Error:', error);
            });
    }

    fetchPartsByStatus(status = 0) {
        // 0: view all, default
        // 1: must order
        // 2: warning
        // 3: ok
        console.log('fetchPartsByStatus ' + status)
        this.fetchParts('', 0, status);
    }

